/**
 * crown.test.ts — BLIND per-unit kit spec (S5 cross-family post-op).
 * Written from Crown's kit prose ALONE; blind to the driver's override/tests/truth file.
 *
 * CROWN (crown) — MG/Iron/Defender/Burst II. Pure SUPPORT: her kit carries ZERO
 * self-damage lines, so her own damage is plain MG normal fire (normalAttackMultiplier
 * 5.57). Every damage-relevant kit line is a buff / weapon-state modifier on ALLIES.
 *
 * Fixture: controlComp('ada'). The fixed control comp is liter B1 / crown B2 / carry B3 /
 * helm B3 — crown is ALREADY the built-in B2, so I do NOT inject her; I pick a simSupported
 * carry (ada) and READ crown's emitted buff events. crown casts her B2 burst every rotation,
 * so her burst block AND skill1 (FB-enter) both fire; a lone B3 would make zero Full Bursts,
 * which is why controlComp supplies B1/B2.
 *
 * Self-identifying crownSlot: crown emits buffApply events with distinctive values
 * (64.51 / 44.35 / 37.44 / 36.24) that no other comp member shares, so crownSlot is the single
 * casterIdx behind those values — no reliance on an index field. (Boss-held debuffs emit
 * casterIdx===null and are filtered out.)
 *
 * Kit lines & why each assertion discriminates:
 *  S1a  ATK \u25b2 64.51% OF THE SKILL USER'S ATK, FB start, bursted allies -> casterAtkPct
 *       (flat add keyed to CROWN's ATK). Nearest-wrong: atkPct (scales the TARGET's own ATK) —
 *       caught by the stat key. Trigger = fullBurstEnter: NO such apply appears before the first
 *       fullBurstStart (nearest-wrong burstCast fires PRE-FB).
 *  S1b  Reload Speed \u25b2 44.35% (both branches -> all allies) -> reloadSpeedPct. Weapon-state
 *       IS damage (gates shots fired): zeroing crown's copy must LOWER team damage. Nearest-wrong
 *       (\"skip, it's defensive\") leaves totals unchanged.
 *  S1c  DEF \u25b2 37.44% of caster's DEF -> offensively INERT in v1 (no DEF->damage path):
 *       present for kit completeness, but zeroing defPct is damage-NEUTRAL.
 *  Bua  Burst Attack Damage \u25b2 36.24%, all allies incl self -> attackDamagePct (Damage Up
 *       bucket): targets >=2 allies incl crownSlot; zeroing it must LOWER team damage.
 *  GAP  Burst Shield 10.45% Max HP -> no HP pool + no 'shield' onEvent kind => unobservable /
 *       offensively inert (it.skip).
 *  GAP  Skill2 Relax heal-stack machine (43 normals/stack x20) + \"when recovery takes effect\"
 *       Attack Damage \u25b2 20.99% (7s) — a real ally damage buff, but chained through a heal event
 *       the sim has no pool/primitive for; unmodelable here (it.skip).
 *
 * ASSUMPTION: withPatchedOverride('crown', mut) returns a clone consumed via
 * CompOptions.overrides. Only the counterfactual (damage-delta) tests depend on that wiring;
 * the existence/stat/trigger/target tests — the core faithfulness signal — do not.
 */
import { describe, it, expect } from 'vitest';
import { controlComp, runComp, totals, withPatchedOverride } from '../lib/harness';

const approx = (a: number, b: number, tol = 0.2) => Math.abs(a - b) <= tol;

function run(opts: any) {
  const order: any[] = [];
  const ev: Record<string, any[]> = {
    shot: [], damage: [], buffApply: [], buffRemove: [], reload: [],
    burstCast: [], fullBurstStart: [], fullBurstEnd: [],
  };
  const res = runComp({
    ...opts,
    cfg: {
      ...(opts.cfg || {}),
      onEvent: (e: any) => { order.push(e); (ev[e.kind] ||= []).push(e); },
    },
  });
  return { res, ev, order };
}

function teamTotal(res: any): number {
  const t: any = totals(res);
  if (typeof t === 'number') return t;
  return Object.values(t).reduce(
    (s: number, v: any) => s + (typeof v === 'number' ? v : (v?.total ?? v?.damage ?? 0)),
    0,
  );
}

// zero every one of CROWN's own buff effects with the given stat (committed JSON untouched)
function zeroCrownStat(carry: string, stat: string) {
  const patched = withPatchedOverride('crown', (ov: any) => {
    for (const b of ov.blocks || []) {
      for (const e of b.effects || []) {
        if (e.kind === 'buff' && e.stat === stat) e.value = 0;
      }
    }
  });
  return { ...controlComp(carry), overrides: { crown: patched } };
}

const CARRY = 'ada';
const CROWN_VALS = [64.51, 44.35, 37.44, 36.24];

// hoisted runs (each is a full 180s sim) — 4 total
const base = run(controlComp(CARRY));
const baseTotal = teamTotal(base.res);
const noReload = run(zeroCrownStat(CARRY, 'reloadSpeedPct'));
const noAD = run(zeroCrownStat(CARRY, 'attackDamagePct'));
const noDef = run(zeroCrownStat(CARRY, 'defPct'));

// self-identify crownSlot from her distinctive buff magnitudes
const crownBuffs = base.ev.buffApply.filter(
  (b) => b.casterIdx != null && CROWN_VALS.some((v) => approx(b.value, v)),
);
const crownSlots = new Set(crownBuffs.map((b) => b.casterIdx));
const crownSlot = [...crownSlots][0];

describe('crown kit spec (blind)', () => {
  it('non-vacuity: FB occurs and crown\u2019s support kit actually fires', () => {
    expect(base.ev.fullBurstStart.length).toBeGreaterThan(0);
    expect(crownBuffs.length).toBeGreaterThan(0);
    // all of crown\u2019s buffs must share ONE caster (else the value-based ID is unsafe)
    expect(crownSlots.size).toBe(1);
  });

  it('S1a: ATK buff is casterAtkPct (of caster ATK), NOT atkPct', () => {
    const atk = base.ev.buffApply.filter(
      (b) => b.casterIdx === crownSlot && approx(b.value, 64.51),
    );
    expect(atk.length).toBeGreaterThan(0);
    // faithful: flat add keyed to crown\u2019s ATK
    expect(atk.every((b) => b.stat === 'casterAtkPct')).toBe(true);
    // nearest-wrong (scales the target\u2019s own ATK) must be absent
    expect(atk.some((b) => b.stat === 'atkPct')).toBe(false);
  });

  it('S1a: trigger is fullBurstEnter (no ATK apply before the first Full Burst)', () => {
    const firstFb = base.order.findIndex((e) => e.kind === 'fullBurstStart');
    const firstAtk = base.order.findIndex(
      (e) => e.kind === 'buffApply' && e.casterIdx === crownSlot && approx(e.value, 64.51),
    );
    expect(firstFb).toBeGreaterThanOrEqual(0);
    expect(firstAtk).toBeGreaterThanOrEqual(0);
    // discriminates fullBurstEnter from the nearest-wrong burstCast (which fires PRE-FB)
    expect(firstAtk).toBeGreaterThan(firstFb);
  });

  it('S1b: Reload Speed is reloadSpeedPct on ALL allies (both branches)', () => {
    const rl = base.ev.buffApply.filter(
      (b) => b.casterIdx === crownSlot && approx(b.value, 44.35),
    );
    expect(rl.length).toBeGreaterThan(0);
    expect(rl.every((b) => b.stat === 'reloadSpeedPct')).toBe(true);
    // bursted + non-bursted branches together cover all allies
    const targets = new Set(rl.map((b) => b.targetIdx));
    expect(targets.size).toBeGreaterThanOrEqual(2);
  });

  it('S1b: reload speed is DAMAGE (gates shots) — zeroing it lowers team damage', () => {
    // nearest-wrong \"defensive, skip\" would leave this unchanged
    expect(baseTotal).toBeGreaterThan(teamTotal(noReload.res));
  });

  it('S1c: DEF buff (37.44% of caster DEF) is present but offensively INERT', () => {
    const def = base.ev.buffApply.filter(
      (b) => b.casterIdx === crownSlot && approx(b.value, 37.44),
    );
    // completeness: the line is represented (stat key not over-constrained—no casterDefPct in v1)
    expect(def.length).toBeGreaterThan(0);
    // inertness: zeroing defPct is damage-neutral (deterministic sim)
    expect(teamTotal(noDef.res)).toBe(baseTotal);
  });

  it('Burst: Attack Damage \u25b2 36.24% is attackDamagePct on all allies incl self', () => {
    const ad = base.ev.buffApply.filter(
      (b) => b.casterIdx === crownSlot && approx(b.value, 36.24),
    );
    expect(ad.length).toBeGreaterThan(0);
    expect(ad.every((b) => b.stat === 'attackDamagePct')).toBe(true);
    const targets = new Set(ad.map((b) => b.targetIdx));
    expect(targets.size).toBeGreaterThanOrEqual(2); // all allies
    expect(targets.has(crownSlot)).toBe(true);      // includes self
  });

  it('Burst: Attack Damage is DAMAGE — zeroing crown\u2019s copy lowers team damage', () => {
    expect(baseTotal).toBeGreaterThan(teamTotal(noAD.res));
  });

  it.skip('Burst Shield (10.45% Max HP): unobservable — no HP pool + no shield onEvent kind; offensively inert', () => {});

  it.skip('S2: Relax heal-stack machine + \"on recovery\" Attack Damage \u25b2 20.99% (7s): heal-triggered, no sim primitive/pool', () => {});
});
